elif [ -f "${_GSD_RUNTIME_ROOT}/.claude/gsd-core/bin/${_GSD_SHIM_NAME}" ]; then GSD_TOOLS="${_GSD_RUNTIME_ROOT}/.claude/gsd-core/bin/${_GSD_SHIM_NAME}"; gsd_run() { node "$GSD_TOOLS" "$@"; }
elif command -v gsd-tools >/dev/null 2>&1; then GSD_TOOLS="$(command -v gsd-tools)"; gsd_run() { "$GSD_TOOLS" "$@"; }
elif [ -f "${CLAUDE_CONFIG_DIR:-$HOME/.claude}/gsd-core/bin/${_GSD_SHIM_NAME}" ]; then GSD_TOOLS="${CLAUDE_CONFIG_DIR:-$HOME/.claude}/gsd-core/bin/${_GSD_SHIM_NAME}"; gsd_run() { node "$GSD_TOOLS" "$@"; }
else echo "ERROR: gsd-tools.cjs not found" >&2; return 1 2>/dev/null || exit 1; fi
_gsd_field() { node -e "const o=JSON.parse(process.argv[1]); const v=o[process.argv[2]]; process.stdout.write(v==null?'':String(v))" "$1" "$2"; }
PRELUDE
echo "written"; git -C /home/janfr/dev/pc-switcher rev-parse --show-toplevel

source /tmp/claude-1000/-home-janfr-dev-pc-switcher/66b3d836-7b8f-417f-a7ce-9a681b81c292/scratchpad/gsd-prelude.sh && echo "GSD_TOOLS=$GSD_TOOLS" && PHASE=2 && INIT=$(gsd_run query init.plan-phase "$PHASE"); if [[ "$INIT" == @file:* ]]; then INIT=$(cat "${INIT#@file:}"); fi; echo "$INIT" > /tmp/claude-1000/-home-janfr-dev-pc-switcher/66b3d836-7b8f-417f-a7ce-9a681b81c292/scratchpad/init.json; node -e "
const o=JSON.parse(require('fs').readFileSync('/tmp/claude-1000/-home-janfr-dev-pc-switcher/66b3d836-7b8f-417f-a7ce-9a681b81c292/scratchpad/init.json','utf8'));
const keys=['researcher_model','planner_model','checker_model','research_enabled','plan_checker_enabled','nyquist_validation_enabled','commit_docs','text_mode','phase_found','phase_dir','expected_phase_dir','phase_number','phase_name','phase_slug','padded_phase','has_research','has_context','has_reviews','has_plans','plan_count','phase_status','planning_exists','roadmap_exists','phase_req_ids','response_language','granularity','state_path','roadmap_path','requirements_path','context_path','research_path','verification_path','uat_path','reviews_path','patterns_path','auto_chain_active','auto_advance'];
