source /tmp/claude-1000/-home-janfr-dev-pc-switcher/66b3d836-7b8f-417f-a7ce-9a681b81c292/scratchpad/gsd-prelude.sh
SP=/tmp/claude-1000/-home-janfr-dev-pc-switcher/66b3d836-7b8f-417f-a7ce-9a681b81c292/scratchpad
gsd_run loop render-hooks plan:pre --raw > "$SP/plan-pre-hooks.json" 2>"$SP/plan-pre-hooks.err"; echo "exit=$?"
wc -c "$SP/plan-pre-hooks.json"; head -c 300 "$SP/plan-pre-hooks.err"
node -e "
const o=JSON.parse(require('fs').readFileSync('$SP/plan-pre-hooks.json','utf8'));
const hooks=o.activeHooks||o.data?.activeHooks||[];
console.log('activeHooks count:', hooks.length);
for(const h of hooks){
  console.log('---');
  console.log('  capId:', h.capId, '| kind:', h.kind, '| id:', h.id||h.name);
  console.log('  blocking:', h.blocking, '| into:', h.into, '| onError:', h.onError);
  console.log('  ref:', JSON.stringify(h.ref));
  console.log('  check:', JSON.stringify(h.check));
  console.log('  configValues:', JSON.stringify(h.configValues));
  console.log('  fragment.inline length:', h.fragment?.inline ? h.fragment.inline.length : 0);
}
console.log('=== top-level keys:', Object.keys(o).join(', '));
"

